/// <summary>
/// Constructs the controller for the batch operation.
/// </summary>
public static ConDemoBatchController construct()
{
    ConDemoBatchController controller = new ConDemoBatchController();
    controller.parmClassName(classStr(ConDemoBatchService));
    controller.parmMethodName(methodStr(ConDemoBatchService, process));
    return controller;
}

/// <summary>
/// Entry point invoked from the menu item.
/// </summary>
public static void main(Args _args)
{
    ConDemoBatchController controller = ConDemoBatchController::construct();
    controller.parmDialogCaption(literalStr("@ConRent:DemoProcessBatch"));
    controller.startOperation();
}
